{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "evidence-matrix.schema.json",
  "type": "object",
  "required": ["status", "coverage_percent", "evidence_rows", "candidate_record_ids", "submitted_record_ids", "unowned_record_ids", "unused_candidate_record_ids", "unused_citations", "missing_evidence", "no_anomaly_coverage", "reconciled_figures", "unresolved_items"],
  "properties": {
    "status": {"enum": ["pass", "blocked"]},
    "coverage_percent": {"type": "number", "minimum": 0, "maximum": 100},
    "evidence_rows": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["anomaly_id", "record_ids", "citations", "facts", "fact_supported", "rule_supported", "coverage_status"],
        "properties": {
          "anomaly_id": {"type": "string", "minLength": 1},
          "record_ids": {
            "type": "array",
            "minItems": 1,
            "uniqueItems": true,
            "items": {"type": "string", "minLength": 1}
          },
          "citations": {
            "type": "array",
            "minItems": 1,
            "items": {
              "type": "object",
              "required": ["doc_id", "clause_no"],
              "properties": {
                "doc_id": {"type": "string", "minLength": 1},
                "clause_no": {"type": "string", "minLength": 1}
              },
              "additionalProperties": false
            }
          },
          "facts": {
            "type": "array",
            "minItems": 1,
            "items": {"type": "string", "minLength": 1}
          },
          "fact_supported": {"const": true},
          "rule_supported": {"const": true},
          "coverage_status": {"const": "pass"}
        }
      }
    },
    "candidate_record_ids": {"type": "array", "uniqueItems": true},
    "submitted_record_ids": {"type": "array", "uniqueItems": true},
    "unowned_record_ids": {"type": "array", "uniqueItems": true},
    "unused_candidate_record_ids": {"type": "array", "uniqueItems": true},
    "unused_citations": {"type": "array"},
    "missing_evidence": {"type": "array"},
    "no_anomaly_coverage": {"type": "object"},
    "reconciled_figures": {"type": "object"},
    "unresolved_items": {"type": "array"}
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "audit-result.schema.json",
  "title": "Unified Audit Result",
  "type": "object",
  "additionalProperties": false,
  "required": ["anomaly_ids", "record_ids", "answer", "citations"],
  "properties": {
    "anomaly_ids": {
      "type": "array",
      "items": {"type": "string", "minLength": 1},
      "uniqueItems": true
    },
    "record_ids": {
      "type": "array",
      "items": {"type": "string", "pattern": "^R[0-9]{6}$"},
      "uniqueItems": true
    },
    "answer": {"type": "string", "minLength": 1},
    "citations": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["doc_id", "clause_no"],
        "properties": {
          "doc_id": {"type": "string", "minLength": 1},
          "clause_no": {"type": "string", "minLength": 1}
        }
      },
      "uniqueItems": true
    }
  }
}

